UPDATE public.featured_samples SET synced_lyrics = '[{"start": 0.92, "end": 4.98, "text": "Six in the morning, you were already up"}, {"start": 7.08, "end": 12.7, "text": "Baking cookies for the nurses, filling up their cups"}, {"start": 13.4, "end": 18.34, "text": "Grey beanie on your head like every Tuesday before"}, {"start": 19.6, "end": 24.16, "text": "You climbed into my car and I couldn''t say a word"}, {"start": 25.62, "end": 30.68, "text": "You grabbed my hand and told me, honey, we''re almost done"}, {"start": 32.22, "end": 36.7, "text": "Comforting me like you''ve always done"}, {"start": 38.22, "end": 43.38, "text": "Eight months of holding on, holding us together"}, {"start": 43.46, "end": 49.8, "text": "Margaret, you made it look like nothing, but I knew better"}, {"start": 50.76, "end": 53.58, "text": "We made it, Mom, we made it through"}, {"start": 55.1, "end": 60.22, "text": "Every waiting room, every Tuesday, every I love you"}, {"start": 60.92, "end": 64.96, "text": "I promised I would find the words when this was done"}, {"start": 66.66, "end": 70.9, "text": "So here I am, still crying, but we won"}, {"start": 71.78, "end": 76.92, "text": "We made it, Mom, we made it home"}, {"start": 77.54, "end": 83.38, "text": "Holding hands and finally letting go"}, {"start": 83.98, "end": 87.64, "text": "Of all that fear I couldn''t say out loud"}, {"start": 89.6, "end": 91.98, "text": "Margaret, I hope I make you proud"}, {"start": 96.5, "end": 100.6, "text": "You told that doctor on the very first day"}, {"start": 101.02, "end": 105.62, "text": "I''m not going anywhere, and you meant what you''d say"}, {"start": 106.56, "end": 108.86, "text": "Still calling me at seven-fifteen"}, {"start": 109.42, "end": 114.66, "text": "Still mailing cards to strangers, still putting us first it seems"}, {"start": 115.44, "end": 120.5, "text": "You lost your hair, your appetite, your strength some days"}, {"start": 121.2, "end": 126.28, "text": "But you never lost yourself, not once, not in any way"}, {"start": 127.76, "end": 132.38, "text": "Worried about Dad eating, worried about the snow"}, {"start": 133.76, "end": 138.68, "text": "Worried about everyone but you, that''s all you know"}, {"start": 140.78, "end": 143.56, "text": "We made it, Mom, we made it through"}, {"start": 145.1, "end": 150.22, "text": "Every waiting room, every Tuesday, every I love you"}, {"start": 150.9, "end": 154.94, "text": "I promised I would find the words when this was done"}, {"start": 156.66, "end": 160.9, "text": "So here I am, still crying, but we won"}, {"start": 161.78, "end": 166.86, "text": "We made it, Mom, we made it home"}, {"start": 167.54, "end": 172.1, "text": "Holding hands and finally letting go"}, {"start": 172.18, "end": 177.64, "text": "Of all that fear I couldn''t say out loud"}, {"start": 179.58, "end": 181.88, "text": "Margaret, I hope I make you proud"}, {"start": 185.14, "end": 187.46, "text": "Sunday dinners still to cook"}, {"start": 187.8, "end": 190.16, "text": "Birthdays you''ll remember in your little book"}, {"start": 190.62, "end": 192.3, "text": "You said you weren''t done yet"}, {"start": 193.58, "end": 195.34, "text": "And Mom, you kept that bet"}, {"start": 196.06, "end": 198.98, "text": "I pulled over on that last drive home"}, {"start": 199.04, "end": 204.34, "text": "''Cause I couldn''t see the road, couldn''t hold it alone"}, {"start": 207.5, "end": 212.8, "text": "But your hand found mine like it always does"}, {"start": 214.04, "end": 218.76, "text": "Quiet about your pain but so loud with your love"}, {"start": 221.78, "end": 224.72, "text": "We made it, Mom, we made it through"}, {"start": 226.1, "end": 231.24, "text": "Every waiting room, every Tuesday, every I love you"}, {"start": 231.9, "end": 235.98, "text": "I promised I would find the words when this was done"}, {"start": 237.66, "end": 241.86, "text": "So here I am, still crying, but we won"}, {"start": 242.76, "end": 247.94, "text": "We made it, Mom, we made it home"}, {"start": 248.54, "end": 254.9, "text": "Holding hands and finally letting go"}, {"start": 254.96, "end": 258.64, "text": "Of all that fear I couldn''t say out loud"}, {"start": 260.58, "end": 262.98, "text": "Margaret, I hope I make you proud"}, {"start": 266.74, "end": 268.86, "text": "That grey beanie''s in the drawer now"}, {"start": 272.7, "end": 276.16, "text": "And I''m calling you at seven-fifteen"}, {"start": 278.54, "end": 281.56, "text": "Just to say good morning, Mom"}, {"start": 283.02, "end": 286.14, "text": "Just to say we made it"}, {"start": 288.68, "end": 289.86, "text": "We made it"}]'::jsonb WHERE id = 'd14f8ca3-ec11-45c7-b52d-a2671284357c';